  payload = '{"species": "Longan", "species_slug": "longan", "varieties": [{"name": "Kohala", "slug": "kohala", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Hawaii, USA (introduced from Southeast Asia, 1954 to Florida)", "traits": "Large fruit (10-12.5g average), medium-sized seed, light thin yellowish-brown skin", "flesh_fruit": "Aromatic, sweet, spicy flavor. Translucent white flesh, soft to medium texture. High aril recovery (60-70%)", "yield_notes": "Reliable blooming and fruiting. Mean yield 15.7 kg/tree. Early season (January-February in Australia)", "growing_notes": "", "availability": ""}, {"name": "Biew Kiew (Biew Khiew)", "slug": "biew-kiew-biew-khiew", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Thailand (major commercial cultivar)", "traits": "Large fruit (average 10-11g, can reach 18g), lopsided shape, thick yellowish-brown skin when ripe, small seed", "flesh_fruit": "Intense sweetness with strong caramel/butterscotch flavor and floral aroma. Thick, crisp, firm texture. Very sweet with aromatic profile. High quality.", "yield_notes": "Heavy consistent cropper. Maximum yield 72kg on 9-year tree recorded. Mean yield 23.4 kg/tree. Late season (March-April in Australia)", "growing_notes": "", "availability": "Available from Queensland nurseries: Daley''s Fruit, The Thorny Fruit Co (Mareeba favorite), specialized tropical fruit nurseries"}, {"name": "Haew (How/Chompoo)", "slug": "haew-how-chompoo", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Thailand", "traits": "Medium to large fruit (15-18g), consistently round shape, slightly thicker skin than other varieties, medium seed", "flesh_fruit": "Notable sweetness with fragrant aroma. Good quality, crisp texture. Popular canning variety in Thailand.", "yield_notes": "Late maturing cultivar. Mean yield 8.3 kg/tree. Tends to alternate bearing (on/off years). Heavy cropper in good years.", "growing_notes": "", "availability": "Available at The Longan Farm Narangba, Daley''s Fruit, humid subtropical climates area fruit tree nurseries"}, {"name": "Homestead", "slug": "homestead", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "Florida, USA/Hawaii selection", "traits": "Medium to large fruit, upright vigorous tree growth", "flesh_fruit": "Acceptable eating quality, sweet flavor, soft texture. Good quality but rated slightly lower than late-season Thai types.", "yield_notes": "Mean yield 8.7 kg/tree. Early season variety (late January-early February). Reliable bearer.", "growing_notes": "", "availability": ""}, {"name": "Kay Sweeney (KSweeney)", "slug": "kay-sweeney-ksweeney", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Hawaiian Islands (seedling of Kohala)", "traits": "Very large fruit (12.5g average - largest of tested varieties), slightly bigger than parent Kohala. Medium/large seed.", "flesh_fruit": "Soft, sweeter flesh. High flesh recovery at 72.2% (highest percentage). Good quality.", "yield_notes": "Early season (late January-early February). Consistent bearer. Only cultivar with significant fruit in largest size category (25-32mm).", "growing_notes": "", "availability": ""}, {"name": "Diamond River", "slug": "diamond-river", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "Thailand (recent introduction to Australia/USA)", "traits": "Medium fruit size, susceptible to limb breakage under heavy crop load", "flesh_fruit": "Award-winning exceptional flavor profile. Fair to good quality. Sweet taste.", "yield_notes": "Fruits every year (no alternate bearing). Precocious - bears early. Produces off-season crops. Late season producer.", "growing_notes": "", "availability": "Available from specialized tropical fruit nurseries in Queensland"}, {"name": "Daw (E-Daw/Edaw)", "slug": "daw-e-daw-edaw", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "Thailand (73% of Thai longan area, most popular Thai cultivar)", "traits": "Large fruit with big seed (15-18g fruit weight), thin skin, thick flesh, greenish new growth. Low aril recovery due to large seed.", "flesh_fruit": "Sweet with good flavor, fairly crisp but not as crispy as Biew Kiew. Thick aromatic flesh. Excellent quality for early season.", "yield_notes": "Early maturing (name means ''early''). Consistent bearer, no alternate bearing problems. Low yield in some locations (1.5 kg/tree in Australia trials). Fruits don''t store well on tree - seeds may germinate in fruit.", "growing_notes": "", "availability": "Limited availability in Australian nurseries, some Queensland specialty suppliers"}, {"name": "Dang (E-Dang/Red Stem)", "slug": "dang-e-dang-red-stem", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "Thailand", "traits": "Medium sized fruit, red new stem growth (hence ''Red Stem'')", "flesh_fruit": "Fair quality, sweet but not particularly crisp. Acceptable eating quality.", "yield_notes": "Heavy-bearing variety. Mean yield 12.7 kg/tree. Late season (mid-July to early August in Thailand; late January-February in Australia).", "growing_notes": "", "availability": "Limited in Australian market, some Queensland tropical fruit specialists"}, {"name": "Sri Chompoo (Pink Flesh/Chompoo)", "slug": "sri-chompoo-pink-flesh-chompoo", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "Thailand", "traits": "Large fruit, greenish-brown to reddish skin when ripe, small seed, red/pink new growth, pink-tinted flesh", "flesh_fruit": "Faint pink tinge in flesh (''Chompoo'' = pink in Thai). High quality, sweet with pleasant aroma. Very ornamental foliage.", "yield_notes": "Maximum yield 76 kg on 6-year tree (highest recorded). Mean yield 25.7 kg/tree (highest average). Late season (March-April). Not preferred for canning due to pink flesh color.", "growing_notes": "", "availability": ""}, {"name": "Ilao", "slug": "ilao", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "Thailand/Southeast Asia", "traits": "Medium fruit size, early-type variety", "flesh_fruit": "Flavor and eating quality similar to late Thai types. Good quality. High percentage parthenocarpic fruit in first season.", "yield_notes": "Early type fruiting. Under evaluation with promising results.", "growing_notes": "", "availability": ""}, {"name": "Duan Yu", "slug": "duan-yu", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 10, "origin": "Thailand", "traits": "Medium sized fruit", "flesh_fruit": "Poor fruit quality - texture and flavor not recommended", "yield_notes": "Mid-season type (mid-February). Mean yield 16.2 kg/tree.", "growing_notes": "", "availability": ""}, {"name": "Pon Yai", "slug": "pon-yai", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 11, "origin": "Thailand", "traits": "Small fruit size, susceptible to pink wax scale and sooty mold", "flesh_fruit": "Poor quality", "yield_notes": "Very poor - lowest yields recorded at 1.7 kg/tree. Mid-season (mid-February).", "growing_notes": "", "availability": "Not commercially available"}, {"name": "Shixia 🏆", "slug": "shixia", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 0, "origin": "Guangdong Province, China - 140+ year history (heirloom variety established ~1880s)", "traits": "Small fruit (12-15g average) but exceptionally high quality. Dense foliage, medium tree height ideal for high-density planting.", "flesh_fruit": "Crisp, thick, very sweet aril. Extremely high TSS (Total Soluble Solids) at 19-20%. Best cultivar for consuming fresh. Excellent flavor - superior quality.", "yield_notes": "Heavy crops regularly on unusually large panicles. High-density system yields 2,250 kg per mu on 8-year trees (120 trees/mu). Most cultivated in Guangdong province.", "growing_notes": "", "availability": "Available from tropical monsoon climates specialty nurseries, Greens of tropical monsoon climates, Indian agricultural research stations"}, {"name": "Chuliang 🏆", "slug": "chuliang", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 1, "origin": "Gaozhou area, Guangdong Province, China (native superior cultivar, long established heritage)", "traits": "Large fruit (12-16.5g average), thick skin. Currently covers over 100,000 ha in China (30,000 ha in Gaozhou alone).", "flesh_fruit": "Thick, firm aril. Very sweet (TSS 20-23%) with fragrant flavor. High aril recovery (69-74% edible portion). Golden yellow when dried. Excellent drying variety.", "yield_notes": "High and stable yield. Output over 60,000 metric tons from 12,000 ha production area. Early bearing, hereditary stability.", "growing_notes": "", "availability": "Greens of tropical monsoon climates, tropical monsoon climates agricultural departments, Indian tropical fruit nurseries"}, {"name": "Wulongling (Black Dragon Peak) 🏆", "slug": "wulongling-black-dragon-peak", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 2, "origin": "Fujian Province, China - 150+ year history (major heirloom cultivar established ~1870s)", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "E-Daw/Yiduo (Edaw) 🌱", "slug": "e-daw-yiduo-edaw", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 3, "origin": "Thailand (tropical ecotype, major export variety - 90% of Thai longan imports to China)", "traits": "Coarse large fruit, thick flesh, small seed, greenish new growth. Vigorous growth, easy flowering.", "flesh_fruit": "Exceptionally sweet, thick aromatic flesh. Crisp, juicy texture. High edible rate. Very high quality.", "yield_notes": "Extremely high - production can reach 2,000-3,000 kg per mu in Thailand. Year-round production possible in Vietnam. Most exported longan variety.", "growing_notes": "", "availability": ""}, {"name": "Ruby Longan", "slug": "ruby-longan", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 4, "origin": "Modern selection/hybrid from tropical breeding programs", "traits": "Ruby red color of fruits and leaves (eye-catching ornamental value), evergreen", "flesh_fruit": "Very juicy and sweet with ruby red color. Translucent flesh with grape-like consistency. Taste resembling lychee and grape. Considered superfood quality.", "yield_notes": "Fruits in 2-3 years from planting. Good productivity.", "growing_notes": "", "availability": ""}, {"name": "Diamond River (Belian) 🧬", "slug": "diamond-river-belian", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "sort_order": 5, "origin": "Thailand (recent introduction, widely tested in tropical regions)", "traits": "Medium fruit, susceptible to limb breakage, precocious", "flesh_fruit": "Award-winning exceptional flavor. Fair to good quality, thick flesh, small seed.", "yield_notes": "Fruits every year without alternate bearing. Off-season production capability. Early bearing. Reported to fruit annually.", "growing_notes": "", "availability": ""}, {"name": "Pingpong 🌱", "slug": "pingpong", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 6, "origin": "Southeast Asia (Malaysia/Thailand selection)", "traits": "Compact growth habit, suitable for small gardens and container growing", "flesh_fruit": "Sweet, aromatic. Good quality for fresh eating.", "yield_notes": "Good yields for tree size. Regular bearer.", "growing_notes": "", "availability": ""}, {"name": "Fuyan (Lucky Eye) 🏆", "slug": "fuyan-lucky-eye", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 7, "origin": "Fujian Province, China (major ancient cultivar, accounts for 90%+ of Fujian plantings)", "traits": "Large fruit (18g average), thin skin, small seed. Over one million trees in cultivation (long history).", "flesh_fruit": "Thick crisp aril. Lower TSS (15-16%) than fresh varieties but excellent for canning. High quality processed product.", "yield_notes": "High yielding. Best cultivar for canning industry.", "growing_notes": "", "availability": ""}, {"name": "Wu Yuan (Wuyuan/Black Round) 🌱", "slug": "wu-yuan-wuyuan-black-round", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 8, "origin": "Guangdong Province, China (important traditional cultivar, introduced to USA in 1930)", "traits": "Medium fruit (15g), large seed. Vigorous tree growth. Used extensively as rootstock for its vigor.", "flesh_fruit": "Soft and juicy aril. Average quality for fresh but excellent for drying. TSS 14-15%. More acidic than other varieties.", "yield_notes": "High yield. Traditional canning variety. Extensively used for vegetative propagation (inarching).", "growing_notes": "", "availability": ""}, {"name": "Fengko (Fukien/Fenke) 🌱", "slug": "fengko-fukien-fenke", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 9, "origin": "Fujian Province, China (introduced to Taiwan 300+ years ago, now 95%+ of Taiwan production)", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Lidongben 🏆", "slug": "lidongben", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "sort_order": 10, "origin": "Fujian Province, China (traditional cultivar, major regional variety)", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Songfengben 🌱", "slug": "songfengben", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 11, "origin": "Fujian Province, China (traditional cultivar)", "traits": "Medium fruit. Highly sensitive to potassium chlorate flowering induction (90%+ flowering rates).", "flesh_fruit": "Good quality. Lowest quercetin content (69.6 µg/g) but still nutritionally valuable.", "yield_notes": "Excellent response to KClO3 treatment allows controlled flowering - can achieve 90%+ flowering rates with proper treatment.", "growing_notes": "", "availability": ""}, {"name": "Dawuyuan 🌱", "slug": "dawuyuan", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 12, "origin": "Guangxi Province, China (major regional cultivar)", "traits": "Medium to large fruit. Well-adapted to Guangxi tropical/subtropical conditions.", "flesh_fruit": "Good quality, sweet flavor suitable for fresh consumption.", "yield_notes": "", "growing_notes": "", "availability": ""}, {"name": "Biew Kiew 🌱", "slug": "biew-kiew", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "sort_order": 12, "origin": "Thailand (major commercial variety, high-yield cultivar)", "traits": "Large fruit (10-18g), lopsided shape, small seed, thick skin (longer shelf life). Dark green leaves, red new growth. One of 4 varieties suitable for Malaysia.", "flesh_fruit": "Intense sweetness, strong caramel flavor, floral aroma. Thick crisp firm texture. Highest quality Thai variety. Thick flesh, small seed ratio.", "yield_notes": "Heavy consistent yields. High productivity. Most widely grown for Thai commercial production.", "growing_notes": "", "availability": ""}, {"name": "Sri Chompoo (Si Chompoo) 🌱", "slug": "sri-chompoo-si-chompoo", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 13, "origin": "Thailand (premium variety, ''Chompoo'' = pink in Thai)", "traits": "Large attractive fruit, rose-tinted/pink color, greenish-brown to reddish skin, small seed. Red/pink new foliage (ornamental).", "flesh_fruit": "Pink-tinted flesh (unique). Mouthwatering sweetness, pleasant aromatic fragrance. Premium quality. Very ornamental.", "yield_notes": "Good productivity. Mid-season. Highly responsive to KClO3 treatment (100% flowering at just 1 g/m²).", "growing_notes": "", "availability": ""}, {"name": "Haew (Water Chestnut) 🌱", "slug": "haew-water-chestnut", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 14, "origin": "Thailand (major commercial variety)", "traits": "Medium to large fruit (15-18g), consistently round, slightly thicker skin, medium seed", "flesh_fruit": "Notable sweetness, fragrant aroma. Crisp quality. Popular canning variety. Good quality.", "yield_notes": "Popular in Thai markets. Late maturing. Pronounced alternate bearing habit. Good yields in ''on'' years.", "growing_notes": "", "availability": ""}, {"name": "Baidum (Black Leaf) 🌱", "slug": "baidum-black-leaf", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 15, "origin": "Thailand (traditional esteemed variety, somewhat undocumented)", "traits": "Dark foliage. Late season variety (late August-September harvest in Thailand).", "flesh_fruit": "Good quality, valued in Thai homeland.", "yield_notes": "Late season extends harvest period. Good productivity.", "growing_notes": "", "availability": ""}, {"name": "Vietnamese Longan var. longepetiolulatus", "slug": "vietnamese-longan-var-longepetiolulatus", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 16, "origin": "Southern Vietnam (indigenous tropical ecotype, distinct from Chinese varieties)", "traits": "True tropical longan adapted to pure monsoonal conditions. Can yield 2-3 crops per year. Smooth yellowish-tan fruit.", "flesh_fruit": "White to off-white or pinkish translucent flesh. Sweet juicy quality.", "yield_notes": "Multiple crops possible (2-3 per year in pure tropical). Year-round availability in Vietnam. Production areas: Mekong Delta, southern provinces.", "growing_notes": "", "availability": ""}, {"name": "Xuong Com Vang (XCV)", "slug": "xuong-com-vang-xcv", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 17, "origin": "Vietnam (Vietnamese commercial variety)", "traits": "Vietnamese selection adapted to Mekong Delta conditions", "flesh_fruit": "Good quality for tropical monsoon regions", "yield_notes": "Requires 24-36 g/m KClO3 for flowering induction. Cultivated commercially in Vietnam.", "growing_notes": "", "availability": ""}, {"name": "Tieu Da Bo (TDB)", "slug": "tieu-da-bo-tdb", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 18, "origin": "Vietnam (Vietnamese commercial cultivar)", "traits": "Vietnamese selection for monsoon production", "flesh_fruit": "Quality suitable for fresh market and processing", "yield_notes": "Requires 20-40 g/m KClO3 treatment. Commercial cultivation in Vietnam.", "growing_notes": "", "availability": ""}, {"name": "Longnhan", "slug": "longnhan", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 19, "origin": "Vietnam", "traits": "High bearing capacity variety", "flesh_fruit": "Good quality", "yield_notes": "Excellent - noted specifically for high bearing capacity. Choice variety for postharvest processing.", "growing_notes": "", "availability": ""}, {"name": "Tieuhue", "slug": "tieuhue", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "sort_order": 20, "origin": "Vietnam (traditional variety)", "traits": "Traditional Vietnamese genetics", "flesh_fruit": "Good quality for tropical regions", "yield_notes": "Choicest variety for postharvest processing in Asia-Pacific region.", "growing_notes": "", "availability": ""}], "variety_count": 34}'::jsonb,
