UPDATE public.garden_import_queue SET
  payload = '{"species": "Lychee", "species_slug": "lychee", "varieties": [{"name": "Kwai Mai Pink", "slug": "kwai-mai-pink", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "China (Guangdong province), ancient cultivar with 500-600 year history. Introduced to Australia in 1930s.", "traits": "Round fruit, red skin with slight orange hue. Medium size, small to medium seed. Distinctive dark green/black tubercle tips near fruit stalk.", "flesh_fruit": "Spicy-sweet flavor, firm flesh, excellent quality. Small seed with high flesh recovery.", "yield_notes": "High productivity, reliable annual bearer.", "growing_notes": "", "availability": ""}, {"name": "Wai Chee", "slug": "wai-chee", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "China (Guangdong province), 500-600 year heritage. Means ''cherished lychee''.", "traits": "Heart-shaped to round fruit. Deep red skin with thick, irregular segments and smooth protuberances. Small, oval leaflets that curve upwards.", "flesh_fruit": "Very sweet and juicy, watery texture when fully ripe. Medium sized fruit, flat shoulders.", "yield_notes": "Very consistent bearer, reliable annual crops with good alternating year yields.", "growing_notes": "", "availability": "Available at Queensland nurseries including Daley''s Fruit Tree Nursery."}, {"name": "Tai So", "slug": "tai-so", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "China, ancient cultivar. First introduced to Hawaii in 1873, to Australia in 1930s.", "traits": "Egg-shaped fruit, distinctive spearhead/chicken-heart shape. Red skin with hairlike sharp protuberances. Large, glossy dark green leaves with upward curl.", "flesh_fruit": "Sweet and aromatic with pleasant flavor. Variable chicken-tongue seed percentage depending on season.", "yield_notes": "Irregular bearing, good crops every 2-3 years. Can produce 10-50kg per 10-year-old tree.", "growing_notes": "", "availability": ""}, {"name": "Bengal", "slug": "bengal", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 3, "origin": "India (historical variety from Bengal region), introduced to Australia in late 1800s.", "traits": "Bright red skin, round to heart-shaped fruit. Large leaflets, mid-green with distinctive twist along length. Sharp-pointed protuberances. Uneven shoulders. Large, bold pointed seed.", "flesh_fruit": "Very sweet with exceptional rose-like fragrance. Classic lychee flavor profile.", "yield_notes": "Irregular growing habit affects production. Rarely produces chicken-tongue seeds.", "growing_notes": "", "availability": ""}, {"name": "Salathiel", "slug": "salathiel", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 4, "origin": "Australia (developed in Australia, surname of developer), introduced within last 50 years.", "traits": "Bright red with smooth skin, slightly lopsided round shape. Small fruit (approximately 30-32mm diameter). Weak vigor, compact tree.", "flesh_fruit": "Very high proportion of small/aborted seeds (near-seedless). Excellent flesh-to-seed ratio. Sweet flavor, good quality.", "yield_notes": "Moderate production.", "growing_notes": "", "availability": "Available at Queensland nurseries including Daley''s Fruit Tree Nursery."}, {"name": "Souey Tung", "slug": "souey-tung", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 5, "origin": "China (Fujian province), relatively young cultivar (approximately 100 years old). First variety cultivated in Australia.", "traits": "Large fruit, red to orange-red skin. Thin skin with obvious suture line. Uneven shoulders. Dominates Fujian province plantings.", "flesh_fruit": "Good flavor and quality. Produces some chicken-tongue seeds.", "yield_notes": "Good productivity.", "growing_notes": "", "availability": ""}, {"name": "Baitaying (Baitangying)", "slug": "baitaying-baitangying", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 6, "origin": "China (Guangdong province), traditional cultivar with 27,000 hectares under cultivation in Guangdong.", "traits": "Medium-sized fruit, red to orange color. Can be stored well for extended periods.", "flesh_fruit": "Good quality flesh with good flavor.", "yield_notes": "Reliable production.", "growing_notes": "", "availability": ""}, {"name": "Chom Pogo (Chompogo)", "slug": "chom-pogo-chompogo", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 7, "origin": "Chinese origin, now grown in Australia.", "traits": "Medium to large red fruit on dome-shaped tree. Fast-growing tree structure.", "flesh_fruit": "Relatively small seed, good flesh recovery. Quality fruit.", "yield_notes": "Reliable production.", "growing_notes": "", "availability": ""}, {"name": "Erdon Lee", "slug": "erdon-lee", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 8, "origin": "Chinese origin, modern introduction to Australia.", "traits": "EXTRA-LARGE fruit - up to 4 times average size (52g average weight, some fruits 60-80g). Dark greenish and red exterior. Rough, wrinkled skin.", "flesh_fruit": "Exceptional quality, super-sized flesh. Dark red color when mature.", "yield_notes": "Good production from marcotted trees.", "growing_notes": "", "availability": ""}, {"name": "Fay Zee Siu", "slug": "fay-zee-siu", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "sort_order": 9, "origin": "China (Guangdong province), traditional cultivar with 27,000 hectares in Guangdong. Recently imported to Australia.", "traits": "Large fruit (24-32g), green speckled skin effect. Red skin with distinctive appearance.", "flesh_fruit": "Excellent eating quality, very sweet taste. Highly regarded in China.", "yield_notes": "Good productivity.", "growing_notes": "", "availability": "Increasingly available at Queensland nurseries as plantings expand."}, {"na